const r=new IntersectionObserver(e=>{e.forEach(t=>{t.isIntersecting&&t.target.classList.add("visible")})},{threshold:.1,rootMargin:"0px 0px -40px 0px"});document.querySelectorAll(".reveal").forEach(e=>r.observe(e));const s=document.getElementById("header"),n=document.getElementById("burger"),o=document.getElementById("nav");window.addEventListener("scroll",()=>{s?.classList.toggle("scrolled",window.scrollY>20)});n?.addEventListener("click",()=>{const e=o?.classList.toggle("open");n.setAttribute("aria-expanded",String(e))});
